mapper.select:
SELECT permission_id, subject_id, tenant_id, building_id, user_id, role_key,
       can_remind, can_offline_proxy, activated_at, expires_at, deactivated_at, status
FROM t_voting_mobilization_permission
WHERE subject_id = #{subjectId}
  AND tenant_id = #{tenantId}
  AND user_id = #{userId}
  AND status = 1
  AND deactivated_at IS NULL
  AND (expires_at IS NULL OR expires_at > #{now}::timestamptz)
ORDER BY building_id ASC
